// 三载体一致:标记→SVG 字符串(默认)或打印机命令流,零 DOM 足迹
import { transform } from 'https://cdn.jsdelivr.net/npm/receiptline@4/+esm';
// command:'svg'(默认)返回可展示的 SVG 字符串;'escpos' 等返回打印机命令
const svg = transform(data.doc, {
  cpl: data.cpl ?? 48,
  encoding: data.encoding ?? 'cp437',
  command: data.command ?? 'svg',
  gradient: data.gradient ?? true,
  upsideDown: data.upsideDown ?? false,
  cutting: data.cutting ?? true
});
// 展示票面:container.innerHTML = svg;(widget 内注入 shadowRoot)
// 驱动打印机:改 command:'escpos' 拿命令字节交打印通道
